import{test,expect}from"@playwright/test";let languages=[{code:"en",name:"English",path:"/"},{code:"es",name:"Spanish",path:"/es/"},{code:"fr",name:"French",path:"/fr/"},{code:"ar",name:"Arabic",path:"/ar/",rtl:!0}],baseUrl="http://localhost:8001";test("Language switcher should be visible on all language versions",async({page:e})=>{for(var t of languages){var a,o=""+baseUrl+t.path,o=(console.log(`Testing language switcher visibility on ${t.name} site: `+o),await e.goto(o,{timeout:3e4,waitUntil:"domcontentloaded"}),await e.screenshot({path:`test-results/language-switcher-${t.code}.png`,fullPage:!1}),e.locator(".language-switcher")),i=(await expect(o).toBeVisible({timeout:5e3}),e.locator(".language-switcher-current .current-language")),n=(await expect(i).toBeVisible({timeout:2e3}),{en:"English",es:"Español",fr:"Français",ar:"العربية"}),n=n[t.code],i=await i.textContent(),i=(console.log(`Current language text: "${i}", Expected: "${n}"`),await o.locator(".language-switcher-current").click(),e.locator(".language-switcher-dropdown"));await expect(i).toBeVisible({timeout:3e3}),await e.screenshot({path:`test-results/language-switcher-dropdown-${t.code}.png`,fullPage:!1});for(a of languages){var l=e.locator(`.language-option[data-lang="${a.code}"]`);await expect(l).toBeVisible({timeout:2e3})}}}),test("Clicking language options navigates to correct language version",async({page:e})=>{await e.goto(baseUrl+"/",{timeout:3e4,waitUntil:"domcontentloaded"});await e.locator(".language-switcher").locator(".language-switcher-current").click();var t=e.locator(".language-switcher-dropdown");await expect(t).toBeVisible({timeout:3e3}),await e.locator('.language-option[data-lang="es"]').click(),await e.waitForURL("**/es/**",{timeout:3e4}),expect(e.url()).toContain("/es/"),await expect(e.locator(".language-switcher")).toBeVisible({timeout:5e3});t=await e.locator(".language-switcher-current .current-language").textContent();console.log(`After navigation, current language text: "${t}"`)});